code.C:
#include <stdio.h>
int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        if (scanf("%d", &N) != 1) break;
        if (N % 2 == 0) {
            printf("true\n");
        } else {
            printf("false\n");
        }
    }
    return 0;
}

